const fs = require('fs');

// Traduzioni complete delle 78 carte (letterali dall'inglese)
const translations = {
  "ar01": { meaning_up: "Abilità, diplomazia, indirizzo, sottigliezza; malattia, dolore, perdita, disastro, insidie dei nemici; fiducia in sé, volontà; il Consultante, se maschio.", meaning_rev: "Medico, Mago, malattia mentale, disonore, inquietudine.", desc: "Una figura giovanile in veste di mago, con il volto del divino Apollo, con sorriso di fiducia e occhi brillanti. Sopra la sua testa è il misterioso segno dello Spirito Santo, il segno della vita, come un cordone infinito, formando la figura 8 in posizione orizzontale. Intorno alla sua vita è una cintura di serpente, il serpente che sembra divorare la sua stessa coda. Questo è familiare alla maggior parte come simbolo convenzionale dell'eternità, ma qui indica più specificamente l'eternità del conseguimento nello spirito. Nella mano destra del Mago è un bastone sollevato verso il cielo, mentre la mano sinistra punta verso la terra. Questo doppio segno è conosciuto nei gradi molto alti dei Misteri Istituiti; mostra la discesa della grazia, della virtù e della luce, tratte dalle cose superiori e derivate alle cose inferiori. Il suggerimento generale è quindi il possesso e la comunicazione dei Poteri e dei Doni dello Spirito. Sul tavolo davanti al Mago sono i simboli dei quattro semi dei Tarocchi, significanti gli elementi della vita naturale, che giacciono come pedine davanti all'adepto, e lui li adatta come vuole. Sotto sono rose e gigli, i flos campi e lilium convallium, trasformati in fiori coltivati, per mostrare la cultura dell'aspirazione. Questa carta significa il movente divino nell'uomo, che riflette Dio, la volontà nella sua liberazione dall'unione con ciò che è sopra. È anche l'unità dell'essere individuale su tutti i piani, e in un senso molto alto è il pensiero, nella sua fissazione. Con ulteriore riferimento a quello che ho chiamato il segno della vita e la sua connessione con il numero 8, si può ricordare che il Gnosticismo cristiano parla della rinascita in Cristo come una trasformazione verso l'Ogdoade. Il numero mistico è chiamato Gerusalemme celeste, la Terra che scorre di Latte e Miele, lo Spirito Santo e la Terra del Signore. Secondo il Martinismo, 8 è il numero di Cristo." },
  "ar02": { meaning_up: "Segreti, mistero, il futuro ancora non rivelato; la donna che interessa il Consultante, se maschio; la Consultante stessa, se femmina; silenzio, tenacia; mistero, saggezza, scienza.", meaning_rev: "Passione, ardore morale o fisico, presunzione, conoscenza superficiale.", desc: "Ha la falce lunare ai piedi, un diadema cornuto sulla testa, con un globo nel mezzo, e una grande croce solare sul petto. Lo scorrimento nelle sue mani è iscritto con la parola Tora, significante la Legge Maggiore, la Legge Segreta e il secondo senso della Parola. È parzialmente coperto dal suo mantello, per mostrare che alcune cose sono implicite e altre parlate. È seduta tra i pilastri bianco e nero--J. e B.--del Tempio mistico, e il velo del Tempio è dietro di lei: è ricamato con palme e melograni. I vestiti sono fluenti e trasparenti, e il mantello suggerisce luce--uno splendore tremolante. È stata chiamata Scienza occulta sulla soglia del Santuario di Iside, ma è realmente la Chiesa Segreta, la Casa che è di Dio e uomo. Rappresenta anche il Secondo Matrimonio del Principe che non è più di questo mondo; è la Sposa spirituale e Madre, la figlia delle stelle e del Giardino Superiore dell'Eden. È, infine, la Regina della luce presa in prestito, ma questa è la luce di tutti. È la Luna nutrita dal latte della Madre Supremale. In un certo senso, è anche la Madre Supremale stessa--cioè, è il riflesso brillante. È in questo senso di riflessione che il suo vero e più alto nome nel simbolismo è Shekinah--la gloria coabitante. Secondo il Kabbalismo, c'è una Shekinah sia sopra che sotto. Nel mondo superiore è chiamata Binah, la Comprensione Supremale che riflette alle emanazioni che sono sotto. Nel mondo inferiore è Malkuth--quel mondo essendo, per questo scopo, inteso come un Regno benedetto che con il quale è reso benedetto essendo la Gloria Dimorante. Misticamente parlando, lo Shekinah è la Sposa Spirituale dell'uomo giusto, e quando legge la Legge lei dà il significato Divino. Ci sono alcuni aspetti in cui questa carta è la più alta e santissima degli Arcani Maggiori." },
  "ar03": { meaning_up: "Fertilità, azione, iniziativa, lunghezza dei giorni; l'ignoto, clandestino; anche difficoltà, dubbio, ignoranza.", meaning_rev: "Luce, verità, lo scioglimento di questioni complicate, pubbliche riunioni; secondo un'altra lettura, vacillazione.", desc: "Una figura maestosa, seduta, con vestiti ricchi e aspetto regale, come di una figlia del cielo e della terra. Il suo diadema è di dodici stelle, raccolte in un grappolo. Il simbolo di Venere è sullo scudo che riposa vicino a lei. Un campo di grano sta maturando davanti a lei, e oltre c'è una cascata d'acqua. Lo scettro che porta è sormontato dal globo di questo mondo. È l'Orto inferiore dell'Eden, il Paradiso Terrestre, tutto ciò che è simboleggiato dalla casa visibile dell'uomo. Non è Regina coeli, ma è ancora refugium peccatorum, la madre fertile di migliaia. Ci sono anche certi aspetti in cui è stata correttamente descritta come desiderio e le ali di esso, come la donna vestita del sole, come Gloria Mundi e il velo del Sanctum Sanctorum; ma non è, posso aggiungere, l'anima che ha raggiunto le ali, a meno che tutto il simbolismo non sia contato in un modo diverso e inusuale. È soprattutto la fecondità universale e il significato esteriore della Parola. Questo è ovvio, perché non c'è messaggio diretto che sia stato dato all'uomo come quello che è portato dalla donna; ma lei non porta stessa la sua interpretazione. In un altro ordine di idee, la carta dell'Imperatrice significa la porta o il cancello mediante il quale si ottiene l'entrata in questa vita, come nel Giardino di Venere; e poi il modo che conduce da lì, in ciò che è oltre, è il segreto noto alla Sacerdotessa: è comunicato da lei agli eletti. La maggior parte delle vecchie attribuzioni di questa carta sono completamente sbagliate sul simbolismo--come, per esempio, la sua identificazione con la Parola, la Natura Divina, la Triade, e così via." },
  "ar04": { meaning_up: "Stabilità, potenza, protezione, realizzazione; una persona grande; aiuto, ragione, convinzione; anche autorità e volontà.", meaning_rev: "Benevolenza, compassione, credito; anche confusione ai nemici, ostruzione, immaturità.", desc: "Ha una forma della Crux ansata come suo scettro e un globo nella sua mano sinistra. È un monarca coronato--imperante, maestoso, seduto su un trono, i cui bracci sono fronteggiati da teste di ariete. È l'esecuzione e la realizzazione, il potere di questo mondo, qui rivestito dei più alti dei suoi attributi naturali. È occasionalmente rappresentato come seduto su una pietra cubica, che, tuttavia, confonde alcune questioni. È il potere virile, al quale l'Imperatrice risponde, e in questo senso è lui che cerca di togliere il Velo di Iside; eppure lei rimane virgo intacta. Si deve intendere che questa carta e quella dell'Imperatrice non rappresentano esattamente la condizione della vita matrimoniale, sebbene questo stato sia implicito. In superficie, come ho indicato, stanno per la regalità mondana, elevata sui seggi dei potenti; ma sopra di questo c'è il suggerimento di un'altra presenza. Significano anche--e la figura maschile specialmente--la regalità superiore, occupando il trono intellettuale. Hereof è il signoraggio del pensiero piuttosto che del mondo animale. Entrambe le personalità, secondo il loro modo, sono 'piene di strane esperienze', ma la loro non è consapevolmente la saggezza che trae da un mondo superiore. L'Imperatore è stato descritto come (a) volontà nella sua forma incarnata, ma questa è solo una delle sue applicazioni, e (b) come un'espressione di virtualità contenute nell'Essere Assoluto--ma questo è fantasia." },
  "ar05": { meaning_up: "Matrimonio, alleanza, cattività, servitù; secondo un altro resoconto, misericordia e bontà; ispirazione; l'uomo a cui il Consultante ricorre.", meaning_rev: "Società, buona intesa, concordia, eccessiva gentilezza, debolezza.", desc: "Indossa la corona tripla ed è seduto tra due pilastri, ma non sono quelli del Tempio che è custodito dalla Sacerdotessa. Nella sua mano sinistra tiene uno scettro terminante nella croce tripla, e con la sua mano destra dà il segno ecclesiastico ben noto che è chiamato quello dell'esoterismo, distinguendo tra la parte manifesta e nascosta della dottrina. È notevole in questa connessione che la Sacerdotessa non fa alcun segno. Ai suoi piedi sono le chiavi incrociate, e due ministri sacerdotali in alba si inginocchiano davanti a lui. È stato solitamente chiamato il Papa, che è un'applicazione particolare dell'ufficio più generale che simboleggia. È il potere dominante della religione esterna, come la Sacerdotessa è il genio prevalente del potere esoterico, ritirato. I significati propri di questa carta hanno subito un'ammucchiatura deplorevole da quasi tutte le mani. Grand Orient dice correttamente che il Gerarca è il potere delle chiavi, la dottrina ortossa estetica, e il lato esteriore della vita che conduce alla dottrina; ma certamente non è il principe della dottrina occulta, come un altro commentatore ha suggerito. È piuttosto la summa totius theologiae, quando ha passato nella massima rigidità dell'espressione; ma simboleggia anche tutte le cose che sono giuste e sacre sul lato manifesto. Come tale, è il canale della grazia che appartiene al mondo dell'istituzione distintamente da quello della Natura, ed è il leader della salvazione per la razza umana in generale. È l'ordine e il capo della gerarchia riconosciuta, che è il riflesso di un'altra e più grande ordine gerarchico; ma può accadere che il pontefice dimentichi il significato di questo suo stato simbolico e agisca come se contenesse all'interno dei suoi propri misure tutto ciò che il suo segno significa o il suo simbolo cerca di mostrare. Non è, come è stato pensato, filosofia--eccetto dal lato teologico; non è ispirazione; e non è religione, sebbene sia una modalità della sua espressione." },
  "ar06": { meaning_up: "Attrazione, amore, bellezza, prove superate.", meaning_rev: "Insuccesso, progetti stolti. Un altro resoconto parla di matrimonio frustrato e contrarietà di ogni genere.", desc: "Il sole brilla nello zenit, e sotto vi è una grande figura alata con le braccia distese, che riversa influenze. In primo piano vi sono due figure umane, maschio e femmina, svestite l'una di fronte all'altra, come Adamo ed Eva quando per la prima volta occupavano il paradiso del corpo terrestre. Dietro l'uomo c'è l'Albero della Vita, che porta dodici frutti, e dietro la donna c'è l'Albero della Conoscenza del Bene e del Male; il serpente si avvolge attorno ad esso. Le figure suggeriscono gioventù, verginità, innocenza e amore prima che sia contaminato dal desiderio materiale grossolano. Questa è semplicemente la carta dell'amore umano, qui presentato come parte della strada, della verità e della vita. Sostituisce, ricorrendo ai principi primi, la vecchia carta del matrimonio, che ho descritto precedentemente, e le successive follie che raffiguravano l'uomo tra il vizio e la virtù. In un senso molto elevato, la carta è un mistero dell'Alleanza e del Sabato. Il suggerimento riguardante la donna è che essa significa quell'attrazione verso la vita sensibile che porta in sé l'idea della Caduta dell'Uomo, ma essa è piuttosto l'operare di una Legge Segreta della Provvidenza che una tentatore volontaria e consapevole. È attraverso la sua presunta caduta che l'uomo alla fine si innalzerà, e solo per mezzo di lei può completarsi. La carta è quindi, a suo modo, un'altra intimazione riguardante il grande mistero della femminilità. I vecchi significati cadono necessariamente a pezzi con le vecchie immagini, ma anche come interpretazioni di queste, alcuni erano di ordine banale e altri erano falsi nel simbolismo." },
  "ar07": { meaning_up: "Soccorso, provvidenza; anche guerra, trionfo, presunzione, vendetta, difficoltà.", meaning_rev: "Tumulto, lite, disputa, litigio, sconfitta.", desc: "Una figura eretta e principesca che porta una spada sguainata e che corrisponde, in linea generale, alla descrizione tradizionale che ho fornito all'inizio. Sulle spalle dell'eroe vittorioso si suppone che siano gli Urim e i Thummim. Ha condotto la cattività in cattività; è conquista su tutti i piani--nella mente, nella scienza, nel progresso, in certi saggi di iniziazione. Ha così risposto alla sfinge, ed è per questo che ho accettato la variazione di Éliphas Lévi; due sfingi quindi trainano il suo carro. È soprattutto il trionfo nella mente. Si deve intendere per questo motivo (a) che la questione della sfinge riguarda un Mistero della Natura e non del mondo della Grazia, a cui il conducente del carro non potrebbe dare risposta; (b) che i piani della sua conquista sono manifesti o esterni e non dentro di sé; (c) che la liberazione che effettua può lasciare se stesso nel vincolo della comprensione logica; (d) che le prove di iniziazione attraverso cui ha passato trionfando devono essere intese fisicamente o razionalmente; e (e) che se venisse ai pilastri di quel Tempio tra cui siede l'Alta Sacerdotessa, non potrebbe aprire il rotolo chiamato Tora, né se lei lo interrogasse potrebbe rispondere. Non è la regalità ereditaria e non è il sacerdozio." },
  "ar08": { meaning_up: "Potenza, energia, azione, coraggio, magnanimità; anche completo successo e onori.", meaning_rev: "Dispotismo, abuso di potere, debolezza, discordia, talvolta anche disgrazia.", desc: "Una donna, sulla cui testa aleggia lo stesso simbolo di vita che abbiamo visto nella carta del Mago, chiude le fauci di un leone. L'unico punto in cui questo disegno differisce dalle presentazioni convenzionali è che la sua benefica fortezza ha già sottomesso il leone, che è condotto da una catena di fiori. Per ragioni che mi soddisfano, questa carta è stata scambiata con quella della giustizia, che è solitamente numerata otto. Poiché la variazione non porta con sé nulla che significhi al lettore, non c'è causa di spiegazione. La Fortezza, in uno dei suoi aspetti più esaltati, è connessa al Mistero Divino dell'Unione; la virtù, naturalmente, opera su tutti i piani, e quindi attinge da tutti nel suo simbolismo. Si connette anche con innocentia inviolata e con la forza che risiede nella contemplazione. Questi significati più alti sono, tuttavia, questioni di inferenza, e non suggerisco che siano trasparenti sulla superficie della carta. Sono intimati in modo celato dalla catena di fiori, che significa, tra molte altre cose, il dolce giogo e il leggero fardello della Legge Divina, quando è stato preso nel cuore dei cuori. La carta non ha nulla a che fare con l'auto-confidenza nel senso ordinario, sebbene sia stato suggerito--ma riguarda la confidenza di coloro la cui forza è Dio, che hanno trovato il loro rifugio in Lui. C'è un aspetto in cui il leone significa le passioni, e colei che è chiamata Fortezza è la natura superiore nella sua liberazione. Ha camminato su aspidi e basilischi e ha calpestato il leone e il drago." },
  "ar09": { meaning_up: "Prudenza, circospezione; anche e specialmente tradimento, dissimulazione, furfanteria, corruzione.", meaning_rev: "Occultamento, disguido, politica, paura, cautela immotivata.", desc: "La variazione dai modelli convenzionali in questa carta è solo che la lampada non è parzialmente avvolta nel mantello del suo portatore, che fonde l'idea dell'Antico dei Giorni con la Luce del Mondo. È una stella che brilla nella lanterna. Ho detto che questa è una carta di conseguimento, e per estendere questo concetto la figura è vista che alza il suo faro su un'eminenza. Quindi l'Eremita non è, come spiegato da Court de Gebelin, un uomo saggio alla ricerca della verità e della giustizia; né è, come propone una spiegazione successiva, un particolare esempio di esperienza. Il suo faro intima che 'dove sono io, voi potete essere anche voi'. È inoltre una carta che è compresa completamente in modo scorretto quando è connessa con l'idea dell'isolamento occulto, come la protezione del magnetismo personale contro l'ammissione. Questo è uno dei rendimenti frivoli che dobbiamo a Éliphas Lévi. È stato adottato dall'Ordine francese del Martinismo e alcuni di noi hanno ascoltato molto della Filosofia Silenziosa e Sconosciuta avvolta dal suo mantello dalla conoscenza dei profani. Nel vero Martinismo, il significato del termine Philosophe inconnu era di un altro ordine. Non si riferiva al celamento previsto dei Misteri Istituiti, tanto meno dei loro sostituti, ma--come la carta stessa--alla verità che i Misteri Divini assicurano la loro propria protezione da coloro che non sono preparati." },
  "ar10": { meaning_up: "Destino, fortuna, successo, elevazione, fortuna, felicità.", meaning_rev: "Aumento, abbondanza, superfluità.", desc: "In questo simbolo ho di nuovo seguito la ricostruzione di Éliphas Lévi, che ha fornito diversi varianti. È legittimo--come ho accennato--usare il simbolismo egiziano quando questo serve il nostro scopo, purché non sia implicita alcuna teoria di origine. Ho, tuttavia, presentato Tifone nella sua forma di serpente. Il simbolismo non è, ovviamente, esclusivamente egiziano, poiché le quattro Creature Viventi di Ezechiele occupano gli angoli della carta, e la ruota stessa segue altre indicazioni di Lévi rispetto alla visione di Ezechiele, come illustrativa della particolare Chiave dei Tarocchi. Con l'occultista francese e nel disegno stesso, l'immagine simbolica rappresenta il moto perpetuo di un universo fluidico e il flusso della vita umana. La Sfinge è l'equilibrio in esso. La traslitterazione di Taro come Rota è iscritta sulla ruota, invertita con le lettere del Nome Divino--per mostrare che la Provvidenza è implicita in tutto. Ma questa è l'intenzione Divina dentro, e l'intenzione simile fuori è esemplificata dalle quattro Creature Viventi. A volte la sfinge è rappresentata coricata su un piedistallo sopra, il che deruba il simbolismo stultificando l'idea essenziale di stabilità in mezzo al movimento. Dietro la nozione generale espressa nel simbolo c'è la negazione del caso e la fatalità che ne è implicita. Si può aggiungere che, dai giorni di Lévi in poi, le spiegazioni occulte di questa carta sono--anche per l'occultismo stesso--di un genere singolarmente fatuo. Si è detto che significa principio, fecondità, onore virile, autorità regnante, ecc. I risultati della comune pratica divinatoria sono meglio di questo sul loro proprio piano." },
  "ar11": { meaning_up: "Equità, rettitudine, probità, esecutivo; trionfo della parte meritevole in legge.", meaning_rev: "Legge in tutti i suoi dipartimenti, complicazioni legali, bigottismo, pregiudizio, eccessiva severità.", desc: "Poiché questa carta segue il simbolismo tradizionale e porta soprattutto i suoi significati ovvi, c'è poco da dire al riguardo al di fuori delle poche considerazioni raccolte nella prima parte, a cui il lettore è rimandato. Sarà visto, tuttavia, che la figura è seduta tra i pilastri, come l'Alta Sacerdotessa, e per questo motivo sembra opportuno indicare che il principio morale che distribuisce ad ogni uomo secondo le sue opere--mentre, naturalmente, è in stretta analogia con cose superiori;--differisce nella sua essenza dalla giustizia spirituale che è implicita nell'idea di elezione. Quest'ultima appartiene a un ordine misterioso della Provvidenza, in virtù del quale è possibile per certi uomini concepire l'idea di dedizione alle cose più alte. L'operazione di ciò è come il respiro dello Spirito dove vuole, e non abbiamo alcun canone di critica o fondamento di spiegazione riguardante. È analogo al possesso dei doni fatati e dei doni alti e dei doni graziosi del poeta: li abbiamo o non li abbiamo, e la loro presenza è tanto misteriosa quanto la loro assenza. La legge della Giustizia non è coinvolta da entrambi gli alti. In conclusione, i pilastri della Giustizia si aprono in un mondo e i pilastri dell'Alta Sacerdotessa in un altro." },
  "ar12": { meaning_up: "Saggezza, circospezione, discernimento, prove, sacrificio, intuizione, divinazione, profezia.", meaning_rev: "Egoismo, la folla, corpo politico.", desc: "La forca da cui è sospeso forma una croce Tau, mentre la figura--dalla posizione delle gambe--forma una croce fylfot. C'è un'aureola intorno alla testa del presunto martire. Dovrebbe essere notato (1) che l'albero del sacrificio è legno vivente, con foglie su di esso; (2) che il volto esprime profondo rapimento, non sofferenza; (3) che la figura, nel suo insieme, suggerisce la vita in sospensione, ma la vita e non la morte. È una carta di profondo significato, ma tutto il significato è velato. Uno dei suoi editori suggerisce che Éliphas Lévi non conosceva il significato, il che è indiscutibile né lo stesso editore. È stata chiamata falsamente una carta di martirio, una carta di prudenza, una carta della Grande Opera, una carta del dovere; ma possiamo esaurire tutte le interpretazioni pubblicate e trovare solo vanità. Dirò molto semplicemente da parte mia che esprime la relazione, in uno dei suoi aspetti, tra il Divino e l'Universo. Colui che può comprendere che la storia della sua natura superiore è incorporata in questo simbolismo riceverà intimazioni riguardanti un grande risveglio che è possibile, e saprà che dopo il Mistero Sacro della Morte c'è un glorioso Mistero della Resurrezione." },
  "ar13": { meaning_up: "Fine, mortalità, distruzione, corruzione; anche, per un uomo, la perdita di un benefattore; per una donna, molte contrarietà; per una fanciulla, fallimento di progetti matrimoniali.", meaning_rev: "Inerzia, sonno, letargia, pietrificazione, sonnambulismo; speranza distrutta.", desc: "Il velo o la maschera della vita è perpetuato nel cambiamento, nella trasformazione e nel passaggio dal inferiore al superiore, e questo è rappresentato più adeguatamente nel Tarocchi rettificati da una delle visioni apocalittiche piuttosto che dalla nozione grezza dello scheletro mietitore. Dietro c'è l'intero mondo dell'ascesa nello spirito. Il misterioso cavaliere si muove lentamente, portando uno stendardo nero ricamato con la Rosa Mistica, che significa la vita. Tra due pilastri sul margine dell'orizzonte brilla il sole dell'immortalità. Il cavaliere non porta arma visibile, ma re e bambino e fanciulla cadono davanti a lui, mentre un prelato con le mani giunte attende la sua fine. Non dovrebbe essere necessario sottolineare che il suggerimento di morte che ho fatto in connessione con la carta precedente dovrebbe essere, naturalmente, inteso misticamente, ma non è il caso in questo caso. Il transito naturale dell'uomo verso il prossimo stadio del suo essere è o può essere una forma del suo progresso, ma l'entrata esotica e quasi sconosciuta, mentre ancora in questa vita, nello stato di morte mistica è un cambiamento nella forma della coscienza e il passaggio in uno stato a cui la morte ordinaria non è né il percorso né il cancello. Le spiegazioni occulte esistenti della 13ª carta sono, nel complesso, migliori del solito, rinascita, creazione, destinazione, rinnovamento, e il resto." },
  "ar14": { meaning_up: "Economia, moderazione, frugalità, gestione, accomodamento.", meaning_rev: "Cose connesse con le chiese, le religioni, le sette, il sacerdozio, talvolta anche il prete che sposerà il Consultante; anche disunione, combinazioni sfortunate, interessi in competizione.", desc: "Un angelo alato, con il segno del sole sulla fronte e sul petto il quadrato e il triangolo del settenario. Parlo di lui nel senso maschile, ma la figura non è né maschio né femmina. Si ritiene che stia versando le essenze della vita da calice a calice. Ha un piede sulla terra e uno sulle acque, illustrando così la natura delle essenze. Un sentiero diretto sale a certe altezze sul margine dell'orizzonte, e sopra c'è una grande luce, attraverso cui si vede vagamente una corona. Di qui c'è una parte del Segreto della Vita Eterna, come è possibile all'uomo nella sua incarnazione. Tutti i simboli convenzionali sono abbandonati qui. Così pure sono i significati convenzionali, che si riferiscono ai cambiamenti nelle stagioni, al movimento perpetuo della vita e persino alla combinazione di idee. È, inoltre, falso dire che la figura simboleggia il genio del sole, sebbene sia l'analogia della luce solare, realizzata nella terza parte della nostra triplicità umana. È chiamato Temperanza fantasticamente, perché, quando il suo governo si ottiene nella nostra coscienza, tempera, combina e armonizza le nature psichica e materiale. Sotto quel governo sappiamo nella nostra parte razionale qualcosa da dove veniamo e dove stiamo andando." },
  "ar15": { meaning_up: "Devastazione, violenza, veemenza, sforzi straordinari, forza, fatalità; ciò che è predestinato ma non per questo male.", meaning_rev: "Fatalità maligna, debolezza, piccolezza, cecità.", desc: "Il disegno è un'accomodazione, media o armonia, tra diversi motivi menzionati nella prima parte. La Capra Cornuta di Mendes, con ali come quelle di un pipistrello, sta in piedi su un altare. Alla fossa dello stomaco c'è il segno di Mercurio. La mano destra è alzata ed estesa, essendo il contrario di quella benedizione che è data dal Gerarca nella quinta carta. Nella mano sinistra c'è una grande fiamma rovesciata verso la terra. Un pentagramma rovesciato è sulla fronte. C'è un anello davanti all'altare, da cui due catene sono portate ai colli di due figure, maschio e femmina. Questi sono analoghi a quelli della quinta carta, come se Adamo ed Eva dopo la Caduta. Di qui è la catena e la fatalità della vita materiale. Le figure hanno la coda, per significare la natura animale, ma c'è intelligenza umana nei volti, e colui che è esaltato sopra loro non deve essere il loro maestro per sempre. Anche ora, è anche uno schiavo, sostenuto dal male che è in lui e cieco alla libertà del servizio. Con più che la sua solita derisione per le arti che pretendeva di rispettare e interpretare come maestro in esse, Éliphas Lévi afferma che la figura Bafometrica è la scienza occulta e la magia. Un altro commentatore dice che nel mondo Divino significa predestinazione, ma non c'è corrispondenza in quel mondo con le cose che sotto sono della bruta. Quello che significa è l'Abitatore sulla Soglia al di fuori del Giardino Mistico quando coloro che hanno mangiato il frutto proibito ne sono scacciati." },
  "ar16": { meaning_up: "Miseria, angoscia, indigenza, avversità, calamità, disgrazia, inganno, rovina. È una carta in particolare di catastrofe imprevista.", meaning_rev: "Secondo un resoconto, lo stesso in misura minore; anche oppressione, imprigionamento, tirannia.", desc: "Le spiegazioni occulte allegate a questa carta sono scarse e per lo più sconcertanti. È inutile indicare che rappresenta l'uomo in tutti i suoi aspetti, perché lo porta come evidenza sulla superficie. Si dice inoltre che contiene il primo allusione a un edificio materiale, ma non concepisco che la Torre sia più o meno materiale dei pilastri che abbiamo incontrato in tre casi precedenti. Non vedo nulla che giustifichi Papus nel supporre che sia letteralmente la caduta di Adamo, ma c'è di più a favore della sua alternativa--che significa la materializzazione della parola spirituale. Il bibliografo Christian immagina che sia la caduta della mente, cercando di penetrare il mistero di Dio. Concordo piuttosto con Grand Orient che è la rovina della Casa di Wei, quando il male ha prevalso in essa, e soprattutto che è la lacerazione di una Casa di Dottrina. Capisco che il riferimento è, tuttavia, a una Casa di Falsità. Illustra anche nel modo più completo la vecchia verità che 'eccetto il Signore costruisca la casa, coloro che la costruiscono si affaticano invano'. C'è un senso in cui la catastrofe è un riflesso dalla carta precedente, ma non dal lato del simbolismo che ho cercato di indicare in essa. È più correttamente una questione di analogia; uno riguarda la caduta nello stato materiale e animale, mentre l'altro significa distruzione dal lato intellettuale. La Torre è stata parlata come il castigo dell'orgoglio e dell'intelletto sopraffatto nel tentativo di penetrare il Mistero di Dio; ma in nessuno dei due casi queste spiegazioni rendono conto delle due persone che sono i sofferenti viventi. Una è la parola letterale resa nulla e l'altra è la sua falsa interpretazione. In un senso ancora più profondo, potrebbe anche significare la fine di una dispensazione, ma non c'è possibilità qui per la considerazione di questa questione complessa." },
  "ar17": { meaning_up: "Perdita, furto, privazione, abbandono; un'altra lettura dice--speranza e prospettive luminose.", meaning_rev: "Arroganza, alterigia, impotenza.", desc: "Una grande stella radiante di otto raggi, circondata da sette stelle minori--anche di otto raggi. La figura femminile in primo piano è completamente nuda. Il suo ginocchio sinistro è sulla terra e il suo piede destro sull'acqua. Versa l'Acqua della Vita da due grandi brocche, irrigando mare e terra. Dietro di lei è un terreno in ascesa e a destra un cespuglio o un albero, su cui un uccello si posa. La figura esprime la gioventù eterna e la bellezza. La stella è l'étoile flamboyante, che appare nel simbolismo massonico, ma è stata confusa in esso. Ciò che la figura comunica alla scena vivente è la sostanza dei cieli e degli elementi. È stato detto correttamente che i motti di questa carta sono 'Acque della Vita liberamente' e 'Doni dello Spirito'. Il riassunto di diverse spiegazioni trasandate dice che è una carta di speranza. Su altri piani è stata certificata come immortalità e luce interiore. Per la maggior parte delle menti preparate, la figura apparirà come il tipo della Verità svelata, gloriosa nella bellezza che non muore, versando sulle acque dell'anima una parte e misura della sua preziosa proprietà. Ma è in realtà la Grande Madre nella Sefirah Kabbalistica Binah, che è la Comprensione Supremale, che comunica alle Sefiroth che sono sotto nella misura in cui possono ricevere il suo influsso." },
  "ar18": { meaning_up: "Nemici nascosti, pericolo, calunnia, oscurità, terrore, inganno, forze occulte, errore.", meaning_rev: "Instabilità, incostanza, silenzio, gradi minori di inganno e errore.", desc: "La distinzione tra questa carta e alcuni dei tipi convenzionali è che la luna sta aumentando su quello che è chiamato il lato della misericordia, a destra dell'osservatore. Ha sedici raggi principali e sedici raggi secondari. La carta rappresenta la vita dell'immaginazione a parte la vita dello spirito. Il sentiero tra le torri è il passaggio verso l'ignoto. Il cane e il lupo sono le paure della mente naturale alla presenza di quel luogo di uscita, quando c'è solo la luce riflessa per guidarla. L'ultimo riferimento è una chiave a un'altra forma di simbolismo. La luce intellettuale è un riflesso e al di là di essa c'è il mistero sconosciuto che non può mostrare. Illumina la nostra natura animale, tipi dei quali sono rappresentati sotto--il cane, il lupo e ciò che sale dalle profondità, la tendenza senza nome e orribile che è più bassa della bestia selvaggia. Si sforza di ottenere la manifestazione, simboleggiata dal strisciare dall'abisso dell'acqua alla terra, ma di regola ricade da dove è venuta. Il volto della mente dirige uno sguardo calmo verso il turbamento sottostante; la rugiada del pensiero cade; il messaggio è: Pace, stai tranquillo; e può accadere che ci sia una calma sulla natura animale, mentre l'abisso sottostante cesserà dal dare forma." },
  "ar19": { meaning_up: "Felicità materiale, matrimonio fortunato, contentezza.", meaning_rev: "Lo stesso in misura minore.", desc: "Il bambino nudo montato su un cavallo bianco e che mostra uno stendardo rosso è stato già menzionato come il migliore simbolismo connesso a questa carta. È il destino del Oriente Soprannaturale e la grande e santa luce che va davanti alla processione infinita dell'umanità, uscendo dal giardino recintato della vita sensibile e procedendo nel viaggio verso casa. La carta significa, quindi, il transito dalla luce manifesta di questo mondo, rappresentato dal glorioso sole della terra, alla luce del mondo a venire, che va davanti all'aspirazione ed è tipizzata dal cuore di un bambino. Ma l'ultima allusione è di nuovo la chiave a una forma diversa o aspetto del simbolismo. Il sole è quello della coscienza nello spirito - il diretto come l'antitesi della luce riflessa. Il tipo caratteristico dell'umanità è diventato un piccolo bambino in esso--un bambino nel senso di semplicità e innocenza nel senso di saggezza. In quella semplicità, porta il sigillo della Natura e dell'Arte; in quella innocenza, significa il mondo restaurato. Quando lo spirito che si conosce ha brillato nella coscienza sopra la mente naturale, quella mente nel suo rinnovamento porta avanti la natura animale in uno stato di perfetta conformità." },
  "ar20": { meaning_up: "Cambiamento di posizione, rinnovamento, esito. Un altro resoconto specifica completa perdita attraverso causa legale.", meaning_rev: "Debolezza, pusillanimità, semplicità; anche deliberazione, decisione, sentenza.", desc: "Ho detto che questo simbolo è essenzialmente invariabile in tutti i set di Tarocchi, o almeno le variazioni non alterano il suo carattere. Il grande angelo è qui circondato da nuvole, ma soffia la sua tromba con stendardo, e la croce come al solito è esposta sullo stendardo. I morti stanno risorgendo dai loro sepolcri--una donna a destra, un uomo a sinistra e tra loro il loro figlio, il cui dorso è rivolto. Ma in questa carta ce ne sono più di tre che sono restaurati, e è stato ritenuto opportuno fare questa variazione come illustrazione dell'insufficienza delle spiegazioni attuali. Dovrebbe essere notato che tutte le figure sono una nella meraviglia, nell'adorazione e nell'estasi espressa dai loro atteggiamenti. È la carta che registra il compimento della grande opera di trasformazione in risposta al sommario del Superno--che il sommario è ascoltato e risposto da dentro. Herein è l'intimazione di un significato che non può essere portato oltre in questo luogo. Cosa è dentro di noi che suona una tromba e tutto ciò che è inferiore nella nostra natura sorge in risposta--quasi in un momento, quasi nel batter d'occhio? Lascia che la carta continui a raffigurare, per coloro che non possono vedere oltre, l'Ultimo Giudizio e la resurrezione nel corpo naturale; ma lasciate che coloro che hanno occhi interiori guardino e scoprire con loro. Capiranno che è stato correttamente chiamato in passato una carta della vita eterna, e per questo motivo può essere paragonato con ciò che va sotto il nome di Temperanza." },
  "ar00": { meaning_up: "Follia, mania, stravaganza, intossicazione, delirio, frenesia, tradimento.", meaning_rev: "Negligenza, assenza, distribuzione, noncuranza, apatia, nullità, vanità.", desc: "Con passo leggero, come se la terra e i suoi vincoli avessero poca potenza di trattenerlo, un giovane uomo in abiti sontuosi si ferma sull'orlo di un precipizio tra le grandi altezze del mondo; scruta la distanza blu davanti a lui--la sua distesa di cielo piuttosto che la prospettiva sottostante. Il suo atto di camminata desiderosa è ancora indicato, sebbene sia fermo nel momento dato; il suo cane è ancora saltando. Il margine che si apre sulla profondità non ha terrore; è come se gli angeli stessero aspettando di sostenerlo, se accadesse che saltasse dall'altezza. Il suo volto è pieno di intelligenza e di sogno atteso. Ha una rosa in una mano e nell'altra un costoso bastone, dal quale pende sulle sue spalle destre un portafoglio curiosamente ricamato. È un principe dell'altro mondo nei suoi viaggi attraverso questo--tutto tra la gloria del mattino, nell'aria fresca. Il sole, che brilla dietro di lui, sa da dove è venuto, dove sta andando, e come tornerà per un altro percorso dopo molti giorni. È lo spirito alla ricerca dell'esperienza. Molti simboli dei Misteri Istituiti sono riassunti in questa carta, che inverte, con alte garanzie, tutte le confusioni che l'hanno preceduto. Nel suo Manuale di Cartomanzia, Grand Orient ha una curiosa suggestione dell'ufficio dello Sciocco Mistico, come parte del suo processo nella divinazione superiore; ma potrebbe richiedere doni più che ordinari per metterlo in operazione. Vedremo come se la cava la carta secondo le arti comuni della lettura del futuro, e sarà un esempio, per coloro che possono discernere, del fatto, altrimenti così evidente, che i Trionfi Maggiori non avevano posto originariamente nelle arti del gioco psichico, quando le carte sono utilizzate come i contatori e i pretesti. Delle circostanze in cui questa arte è nata sappiamo, tuttavia, molto poco. Le spiegazioni convenzionali dicono che lo Sciocco significa la carne, la vita sensibile, e per una particolare satira il suo nome sussidiario era una volta l'alchimista, come raffigurante la follia allo stadio più insensato." },
  "ar21": { meaning_up: "Sicuro successo, ricompensa, viaggio, rotta, emigrazione, fuga, cambio di luogo.", meaning_rev: "Inerzia, fissità, stagnazione, permanenza.", desc: "Poiché questo messaggio finale dei Trionfi Maggiori è invariato--e infatti immutabile--rispetto al suo disegno, è stato descritto in parte già riguardante il suo senso più profondo. Rappresenta anche la perfezione e la fine del Cosmo, il segreto che è dentro, il rapimento dell'universo quando si comprende in Dio. È inoltre lo stato dell'anima nella coscienza della Visione Divina, riflessa dallo spirito che si conosce. Ma questi significati sono senza pregiudizio a ciò che ho detto riguardante da parte materiale. Ha più di un messaggio dal lato macrocosmico ed è, per esempio, lo stato del mondo restaurato quando la legge della manifestazione sarà stata portata al più alto grado della perfezione naturale. Ma è forse più specialmente una storia del passato, riferendosi a quel giorno quando tutto è stato dichiarato buono, quando le stelle del mattino cantavano insieme e tutti i Figli di Dio gridavano di gioia. Una delle peggiori spiegazioni riguardanti è che la figura simboleggia il Mago quando ha raggiunto il più alto grado di iniziazione; un altro racconto dice che rappresenta l'assoluto, il che è ridicolo. La figura è stata detta stare per la Verità, che è, tuttavia, più propriamente allocata alla diciassettesima carta. Infine, è stata chiamata la Corona dei Magi." },
  "wapa": { meaning_up: "Giovane uomo scuro, fedele, un amante, un inviato, un postino. Accanto a un uomo, porterà una testimonianza favorevole su di lui. Un rivale pericoloso, se seguito dal Paggio di Coppe. Ha le qualità principali del suo seme. Potrebbe significare intelligenza familiare.", meaning_rev: "Aneddoti, annunci, cattive notizie. Anche indecisione e l'instabilità che l'accompagna.", desc: "In una scena simile alla precedente, un giovane uomo sta nel atto di proclamazione. È sconosciuto ma fedele, e le sue notizie sono strane." },
  "wakn": { meaning_up: "Partenza, assenza, fuga, emigrazione. Un giovane uomo scuro, amichevole. Cambio di residenza.", meaning_rev: "Rottura, divisione, interruzione, discordia.", desc: "È mostrato come se fosse in viaggio, armato di un corto bastone, e sebbene rivestito non è in un'impresa bellicosa. Sta passando tumuli o piramidi. Il movimento del cavallo è una chiave al carattere del suo cavaliere, e suggerisce l'umore precipitato, o cose ad esso connesse." },
  "waqu": { meaning_up: "Una donna scura, contadina, amichevole, casta, amorosa, onorevole. Se la carta accanto a lei significa un uomo, lei è ben disposta verso di lui; se una donna, lei è interessata al Consultante. Anche, amore del denaro, o un certo successo negli affari.", meaning_rev: "Buono, economico, obbligante, servizievole. Significa anche--ma in certe posizioni e nel vicinato di altre carte che tendono in tali direzioni--opposizione, gelosia, persino inganno e infedeltà.", desc: "I Bastoni in tutto questo seme sono sempre in foglia, poiché è un seme di vita e animazione. Emotivamente e altrimenti, la personalità della Regina corrisponde a quella del Re, ma è più magnetica." },
  "waki": { meaning_up: "Uomo scuro, amichevole, contadino, generalmente sposato, onesto e coscienzioso. La carta significa sempre onestà, e potrebbe significare notizie riguardanti un'eredità inaspettata che cadrà in breve tempo.", meaning_rev: "Buono, ma severo; austero, eppure tollerante.", desc: "La natura fisica e emotiva a cui questa carta è attribuita è scura, ardente, agile, animata, appassionata, nobile. Il Re solleva un bastone fiorito, e indossa, come i suoi tre corrispondenti nei semi rimanenti, quello che è chiamato un berretto di mantenimento sotto la sua corona. Si connette con il simbolo del leone, che è ricamato sul retro del suo trono." },
  "waac": { meaning_up: "Creazione, invenzione, impresa, i poteri che risultano da queste; principio, inizio, fonte; nascita, famiglia, origine, e in un senso la virilità che è dietro di loro; il punto di partenza delle imprese; secondo un altro resoconto, denaro, fortuna, eredità.", meaning_rev: "Caduta, decadenza, rovina, perdizione, perire; anche una certa gioia offuscata.", desc: "Una mano che esce da una nuvola afferra un robusto bastone o clava." },
  "wa02": { meaning_up: "Tra le letture alternative non è possibile matrimonio; da una parte, ricchezze, fortuna, magnificenza; dall'altra, sofferenza fisica, malattia, dispiacere, tristezza, mortificazione. Il disegno dà un suggerimento; qui c'è un signore che guarda il suo dominio e alternatamente contempla un globo; sembra la malattia, la mortificazione, la tristezza di Alessandro in mezzo alla grandezza della ricchezza di questo mondo.", meaning_rev: "Sorpresa, meraviglia, incantesimo, emozione, difficoltà, paura.", desc: "Un uomo alto guarda da un tetto fortificato sul mare e la spiaggia; tiene un globo nella mano destra, mentre un bastone nella sua sinistra riposa sul coronamento; un altro è fissato in un anello. La Rosa e la Croce e il Giglio dovrebbero essere notati sul lato sinistro." },
  "wa03": { meaning_up: "Simboleggia la forza stabilita, l'impresa, lo sforzo, il commercio, la scoperta; queste sono le sue navi, che portano la sua merce, che stanno navigando sul mare. La carta significa anche cooperazione capace negli affari, come se il mercante principe di successo stesse guardando dal suo lato verso il tuo con l'intenzione di aiutarti.", meaning_rev: "La fine dei guai, la sospensione o la cessazione dell'avversità, della fatica e della delusione.", desc: "Una persona calma e maestosa, con il dorso girato, guardando dal bordo di una scogliera le navi che passano sul mare. Tre bastoni sono piantati nel terreno, e lui si appoggia leggermente su uno di loro." },
  "wa04": { meaning_up: "Sono quasi sulla superficie per una volta--vita di campagna, porto di rifugio, una specie di raccolta domestica, riposo, concordia, armonia, prosperità, pace, e il lavoro perfezionato di questi.", meaning_rev: "Il significato rimane invariato; è prosperità, aumento, felicità, bellezza, abbellimento.", desc: "Dai quattro grandi bastoni piantati in primo piano c'è una grande ghirlanda sospesa; due figure femminili sollevano mazzetti di fiori; al loro fianco c'è un ponte su un fossato, che conduce a un'antica casa signorile." },
  "wa05": { meaning_up: "Imitazione, come, per esempio, combattimento simulato, ma anche la competizione strenua e la lotta della ricerca di ricchezze e fortuna. In questo senso si connette con la battaglia della vita. Da qui alcuni attributi dicono che è una carta d'oro, guadagno, opulenza.", meaning_rev: "Contenzioso, dispute, inganno, contraddizione.", desc: "Una schiera di giovani, che brandiscono bastoni, come se in sport o lite. È una guerra mimica, e a ciò corrispondono" },
  "wa06": { meaning_up: "La carta è stata progettata in modo da poter coprire diversi significati; in superficie, è un vincitore che trionfa, ma è anche grande notizia, come quella che potrebbe essere portata nello stato dal corriere del Re; è l'aspettativa coronata dal suo stesso desiderio, la corona della speranza, e così via.", meaning_rev: "Apprensione, paura, come di un nemico vittorioso alle porte; tradimento, slealtà, come di porte che si aprono al nemico; anche rinvio indefinito.", desc: "Un cavaliere di alloro porta un bastone adorno di una corona di alloro; fanti con bastoni sono al suo fianco." },
  "wa07": { meaning_up: "È una carta di valore, poiché in superficie, sei stanno attaccando uno, che ha, tuttavia, la posizione di vantaggio. Sul piano intellettuale, significa discussione, lite verbale; negli affari--negoziazioni, guerra commerciale, baratto, competizione. È inoltre una carta di successo, poiché il combattente è in cima e i suoi nemici potrebbero non essere in grado di raggiungerlo.", meaning_rev: "Perplessità, imbarazzi, ansia. È anche un'avvertenza contro l'indecisione.", desc: "Un giovane uomo su un'eminenza scoscesa brandisce un bastone; sei altri bastoni sono sollevati verso di lui da sotto." },
  "wa08": { meaning_up: "Attività nelle imprese, il percorso di tale attività, velocità, come quella di un corriere espresso; grande fretta, grande speranza, velocità verso un fine che promette felicità assicurata; generalmente, quello che è in movimento; anche le frecce dell'amore.", meaning_rev: "Frecce di gelosia, disputa interna, punture di coscienza, litigi; e dispute domestiche per persone che sono sposate.", desc: "La carta rappresenta il movimento attraverso l'immobile--un volo di bastoni attraverso un paese aperto; ma si avvicinano al termine del loro corso. Quello che significano è a portata di mano; potrebbe essere anche sulla soglia." },
  "wa09": { meaning_up: "La carta significa forza in opposizione. Se attaccato, la persona affronterà un assalto coraggiosamente; e la sua struttura mostra che potrebbe rivelarsi un antagonista formidabile. Con questo significato principale ci sono tutti i suoi possibili aggiunti--ritardo, sospensione, rinvio.", meaning_rev: "Ostacoli, avversità, calamità.", desc: "La figura si appoggia sul suo bastone e ha uno sguardo atteso, come se aspettasse un nemico. Dietro ci sono otto altri bastoni--eretti, in disposizione ordinata, come una palizzata." },
  "wa10": { meaning_up: "Una carta di molti significati, e alcuni dei significati non possono essere armonizzati. Metto da parte quello che la connette con l'onore e la buona fede. Il significato principale è semplicemente oppressione, ma è anche fortuna, guadagno, qualsiasi tipo di successo, e allora è l'oppressione di queste cose. È anche una carta di apparenza falsa, disguido, perfidia. Il luogo a cui la figura si sta avvicinando potrebbe soffrire dai bastoni che porta. Il successo è reso vano se segue il Nove di Spade, e se è una questione di causa legale, ci sarà certa perdita.", meaning_rev: "Contrarietà, difficoltà, intrighi, e loro analoghi.", desc: "Un uomo oppresso dal peso dei dieci bastoni che sta portando." },
  "cupa": { meaning_up: "Giovane uomo equo, uno spinto a rendere servizio e con cui il Consultante sarà connesso; un giovane studioso; notizia, messaggio; applicazione, riflessione, meditazione; anche queste cose dirette agli affari.", meaning_rev: "Gusto, inclinazione, attaccamento, seduzione, inganno, artificio.", desc: "Un paggio equo, piacevole, piuttosto effeminato, di aspetto studioso e intento, contempla un pesce che sorge da un calice per guardarlo. È l'immagine della mente che prende forma." },
  "cukn": { meaning_up: "Arrivo, avvicinamento--talvolta quello di un messaggero; avanzate, proposte, comportamento, invito, incitamento.", meaning_rev: "Inganno, artificio, sottigliezza, frode, duplicità, frode.", desc: "Elegante, ma non bellicoso; cavalcando tranquillamente, indossando un elmo alato, riferendosi a quelle grazie superiori dell'immaginazione che talvolta caratterizzano questa carta. Anche lui è un sognatore, ma le immagini del lato del senso lo tormentano nella sua visione." },
  "cuqu": { meaning_up: "Buona, donna equa; donna onesta, devota, che renderà servizio al Consultante; intelligenza amorosa, e quindi il dono della visione; successo, felicità, piacere; anche saggezza, virtù; un coniuge perfetto e una buona madre.", meaning_rev: "I resoconti variano; donna buona; altrimenti, donna distinta ma una di cui non ci si può fidare; donna perversa; vizio, disonore, depravazione.", desc: "Bella, equa, sognante--come una che vede visioni in un calice. Questo è, tuttavia, solo uno dei suoi aspetti; vede, ma agisce anche, e la sua attività alimenta il suo sogno." },
  "cuki": { meaning_up: "Uomo equo, uomo di affari, legge, o divinità; responsabile, disposto a obbligare il Consultante; anche equità, arte e scienza, inclusi coloro che professano scienza, legge e arte; intelligenza creativa.", meaning_rev: "Uomo disonesto, doppio; brigantaggio, esazione, ingiustizia, vizio, scandalo, saccheggio, perdita considerevole.", desc: "Tiene uno scettro corto nella mano sinistra e un grande calice nella mano destra; il suo trono è posto sul mare; da un lato una nave sta navigando e dall'altro un delfino sta saltando. L'implicito è che il Segno del Calice si riferisce naturalmente all'acqua, che appare in tutte le carte della corte." },
  "cuac": { meaning_up: "Casa del cuore vero, gioia, contentezza, dimora, nutrimento, abbondanza, fertilità; Tavola Santa, felicità di questa.", meaning_rev: "Casa del cuore falso, mutamento, instabilità, rivoluzione.", desc: "Le acque sono sotto, e su di esse ci sono ninfee; la mano esce dalla nuvola, tenendo nel palmo il calice, dal quale quattro fiumi stanno versando; una colomba, che porta il becco un Ospite marcato da una croce, scende a mettere l'Ostia nel Calice; la rugiada dell'acqua cade da tutti i lati. È un'intimazione di quello che potrebbe stare dietro gli Arcani Minori." },
  "cu02": { meaning_up: "Amore, passione, amicizia, affinità, unione, concordia, simpatia, l'interrelazione dei sessi, e--come un suggerimento a parte da tutti gli uffici della divinazione--quel desiderio che non è nella Natura, ma da cui la Natura è santificata.", meaning_rev: "Lussuria, cupidigia, gelosia, desiderio, brama, ma la carta può anche dare, dice W., 'quel desiderio che non è nella natura, ma da cui la natura è santificata'.", desc: "Un giovane e una fanciulla si impegnano l'uno con l'altro, e sopra i loro calici sorge il Caduceo di Ermete, tra le grandi ali del quale appare la testa di un leone. È una variante di un segno che si trova in pochi vecchi esempi di questa carta. Alcuni significati emblematici curiosi sono allegati ad esso, ma non riguardano noi in questo luogo." },
  "cu03": { meaning_up: "La conclusione di qualsiasi questione in abbondanza, perfezione e allegria; esito felice, vittoria, compimento, sollievo, guarigione.", meaning_rev: "Spedizione, invio, realizzazione, fine. Significa anche il lato dell'eccesso nel godimento fisico, e i piaceri dei sensi.", desc: "Fanciulle in un giardino con calici sollevati, come se si impegnassero l'uno con l'altro." },
  "cu04": { meaning_up: "Stanchezza, disgusto, avversione, vexazioni immaginarie, come se il vino di questo mondo avesse causato solo sazietà; un altro vino, come se un dono di fata, è ora offerto al relitto, ma non vede consolazione in esso. Questa è anche una carta di piacere mescolato.", meaning_rev: "Novità, presagio, nuovo insegnamento, nuove relazioni.", desc: "Un giovane uomo è seduto sotto un albero e contempla tre calici posti sull'erba davanti a lui; un braccio che esce da una nuvola gli offre un altro calice. La sua espressione nonostante sia uno di scontento con il suo ambiente." },
  "cu05": { meaning_up: "Una figura scura e ammantata, che guarda lateralmente tre calici capovolti; altri due stanno in piedi dietro di lui; un ponte è sullo sfondo, che conduce a una piccola torre o proprietà. Significati divinatori: È una carta di perdita, ma qualcosa rimane; tre sono stati presi, ma due rimangono; è una carta di eredità, patrimonio, trasmissione, ma non corrispondente alle aspettative; con alcuni interpreti è una carta di matrimonio, ma non senza amarezza o frustrazione.", meaning_rev: "Notizie, alleanze, affinità, consanguineità, ancestralità, ritorno, progetti falsi.", desc: "Una figura scura e ammantata, che guarda lateralmente tre calici capovolti; altri due stanno in piedi dietro di lui; un ponte è sullo sfondo, che conduce a una piccola torre o proprietà. Significati divinatori: È una carta di perdita, ma qualcosa rimane; tre sono stati presi, ma due rimangono; è una carta di eredità, patrimonio, trasmissione, ma non corrispondente alle aspettative; con alcuni interpreti è una carta di matrimonio, ma non senza amarezza o frustrazione. Rovesciato: Notizie, alleanze, affinità, consanguineità, ancestralità, ritorno, progetti falsi." },
  "cu06": { meaning_up: "Una carta del passato e dei ricordi, guardando indietro, come--per esempio--nell'infanzia; felicità, godimento, ma proveniente piuttosto dal passato; cose che si sono dissolte. Un'altra lettura inverte questo, dando nuove relazioni, nuove conoscenze, nuovo ambiente, e poi i bambini si divertono in un luogo sconosciuto.", meaning_rev: "Il futuro, il rinnovamento, ciò che avverrà a breve.", desc: "Bambini in un vecchio giardino, i loro calici pieni di fiori." },
  "cu07": { meaning_up: "Favori fatati, immagini di riflessione, sentimento, immaginazione, cose viste nel vetro della contemplazione; alcuni risultati in questi gradi, ma nulla di permanente o sostanziale è suggerito.", meaning_rev: "Desiderio, volontà, determinazione, progetto.", desc: "Strani calici di visione, ma le immagini sono più specialmente quelle dello spirito fantastico." },
  "cu08": { meaning_up: "La carta parla da sé in superficie, ma altre letture sono completamente antitetiche--dando gioia, dolcezza, timidità, onore, modestia. In pratica, di solito si trova che la carta mostra il declino di una questione, o che una questione che è stata considerata importante è in realtà di scarsa conseguenza--per il bene o il male.", meaning_rev: "Grande gioia, felicità, festa.", desc: "Un uomo di aspetto scoraggiato sta abbandonando i calici della sua felicità, impresa, impresa o precedente preoccupazione." },
  "cu09": { meaning_up: "Concordia, contentezza, ben-être fisico; anche vittoria, successo, vantaggio; soddisfazione per il Consultante o la persona per cui viene fatta la consultazione.", meaning_rev: "Verità, lealtà, libertà; ma le letture variano e includono errori, imperfezioni, ecc.", desc: "Una persona di bell'aspetto ha banchettato al contenuto del suo cuore, e abbondante rinfresco di vino è sul bancone ad arco dietro di lui, sembrando indicare che anche il futuro è assicurato. L'immagine offre solo il lato materiale, ma ci sono altri aspetti." },
  "cu10": { meaning_up: "Contentezza, riposo del cuore intero; la perfezione di quello stato; anche perfezione dell'amore umano e dell'amicizia; se con diverse carte della corte, una persona che sta prendendo carico degli interessi del Consultante; anche la città, il villaggio o il paese abitati dal Consultante.", meaning_rev: "Riposo del cuore falso, indignazione, violenza.", desc: "Apparenza di Calici in un arcobaleno; è contemplato con meraviglia e estasi da un uomo e una donna sotto, evidentemente marito e moglie. Il suo braccio destro è intorno a lei; il suo sinistro è sollevato verso l'alto; lei solleva il suo braccio destro. I due bambini che ballano vicino a loro non hanno osservato il prodigio ma sono felici a loro modo. C'è una scena domestica oltre." },
  "pepa": { meaning_up: "Applicazione, studio, borsa di studio, riflessione; un'altra lettura dice notizie, messaggi e colui che li porta; anche governo, gestione.", meaning_rev: "Prodigalità, dissipazione, liberalità, lusso; notizie sfavorevoli.", desc: "Una figura giovanile che guarda intensamente al pentacolo che aleggia sopra le sue mani sollevate. Si muove lentamente, insensibile a quello che è intorno a lui." },
  "pekn": { meaning_up: "Utilità, servizievole, interesse, responsabilità, rettitudine--tutto sul piano normale ed esterno.", meaning_rev: "Inerzia, ozio, riposo di quel genere, stagnazione; anche placidità, scoraggiamento, noncuranza.", desc: "Cavalca un cavallo lento, resistente e pesante, al quale il suo stesso aspetto corrisponde. Esibisce il suo simbolo, ma non guarda in esso." },
  "pequ": { meaning_up: "Opulenza, generosità, magnificenza, sicurezza, libertà.", meaning_rev: "Malvagità, sospetto, sospensione, paura, sfiducia.", desc: "Il volto suggerisce quella di una donna scura, le cui qualità potrebbero essere riassunte nell'idea di grandezza d'anima; ha anche il serio carattere dell'intelligenza; contempla il suo simbolo e può vederne i mondi." },
  "peki": { meaning_up: "Valore, intelligenza realizzante, affari e attitudine intellettuale normale, talvolta doni matematici e risultati di questo genere; successo in questi percorsi.", meaning_rev: "Vizio, debolezza, bruttezza, perversità, corruzione, pericolo.", desc: "La figura non richiede una descrizione speciale; il volto è piuttosto scuro, suggerendo anche coraggio, ma in qualche modo letargico nella tendenza. La testa del toro dovrebbe essere notata come un simbolo ricorrente sul trono. Il segno di questo seme è rappresentato in tutto come inciso o blasonato con il pentagramma, tipizzando la corrispondenza dei quattro elementi nella natura umana e quella per cui potrebbero essere governati. In molti vecchi mazzi di Tarocchi questo seme stava per moneta corrente, denaro, denari. Non ho inventato la sostituzione di pentacoli e non ho una causa speciale da sostenere riguardante l'alternativa. Ma il consenso dei significati divinatori è dalla parte di un certo cambiamento, perché le carte non trattano specialmente di questioni di denaro." },
  "peac": { meaning_up: "Contentezza perfetta, felicità, estasi; anche intelligenza veloce; oro.", meaning_rev: "Il lato malvagio della ricchezza, cattiva intelligenza; anche grandi ricchezze. In ogni caso mostra prosperità, condizioni materiali confortevoli, ma se queste sono vantaggiose per il possessore dipenderà dal fatto che la carta sia rovesciata o meno.", desc: "Una mano--che esce, come al solito, da una nuvola--tiene in alto un pentacolo." },
  "pe02": { meaning_up: "Da una parte è rappresentato come una carta di allegria, ricreazione e le sue connessioni, che è il soggetto del disegno; ma è letto anche come notizie e messaggi per iscritto, come ostacoli, agitazione, difficoltà, imbarazzo.", meaning_rev: "Allegria forzata, godimento simulato, senso letterale, grafia, composizione, lettere di cambio.", desc: "Un giovane uomo, nell'atto di danzare, ha un pentacolo in ciascuna mano, e sono uniti da quel cordone infinito che è come il numero 8 rovesciato." },
  "pe03": { meaning_up: "Mestiere, commercio, lavoro specializzato; di solito, tuttavia, considerato come una carta di nobiltà, aristocrazia, rinomanza, gloria.", meaning_rev: "Mediocrità, nel lavoro e altrimenti, puerilità, piccolezza, debolezza.", desc: "Uno scultore al suo lavoro in un monastero. Confronta il disegno che illustra l'Otto di Pentacoli. L'apprendista o l'amatore in esso ha ricevuto la sua ricompensa ed è ora al lavoro sul serio." },
  "pe04": { meaning_up: "La certezza dei possedimenti, aggrapparsi a quello che si ha, dono, eredità, eredità.", meaning_rev: "Sospensione, ritardo, opposizione.", desc: "Una figura coronata, avendo un pentacolo sopra la sua corona, abbraccia un altro con le mani e le braccia; due pentacoli sono sotto i suoi piedi. Si aggrappa a quello che ha." },
  "pe05": { meaning_up: "La carta predice difficoltà materiale soprattutto, sia nella forma illustrata--cioè, destituzione--o altrimenti. Per alcuni cartomanti, è una carta di amore e amanti--moglie, marito, amico, amante; anche concordanza, affinità. Queste alternative non possono essere armonizzate.", meaning_rev: "Disordine, caos, rovina, discordia, dissolutezza.", desc: "Due mendicanti in una tempesta di neve passano da una finestra illuminata." },
  "pe06": { meaning_up: "Regali, doni, gratificazione; un'altra spiegazione dice attenzione, vigilanza; ora è il tempo accettato, prosperità presente, ecc.", meaning_rev: "Desiderio, cupidigia, invidia, gelosia, illusione.", desc: "Una persona con le sembianze di un mercante pesa il denaro in un paio di bilance e lo distribuisce ai bisognosi e agli afflitti. È una testimonianza del suo stesso successo nella vita, così come della sua bontà di cuore." },
  "pe07": { meaning_up: "Questi sono straordinariamente contraddittori; principalmente, è una carta di denaro, affari, baratto; ma una lettura dà alterazione, litigio--e un'altra innocenza, ingegno, purgazione.", meaning_rev: "Causa di ansia riguardante il denaro che si propone di prestare.", desc: "Un giovane uomo, appoggiarsi al suo bastone, guarda intensamente sette pentacoli attaccati a un ciuffo di verdure alla sua destra; si potrebbe dire che questi erano i suoi tesori e che il suo cuore era lì." },
  "pe08": { meaning_up: "Lavoro, occupazione, commissione, artigianato, abilità nell'artigianato e negli affari, forse nello stadio preparatorio.", meaning_rev: "Ambizione annullata, vanità, cupidigia, esazione, usura. Potrebbe anche significare il possesso di abilità, nel senso della mente ingegnosa rivolta all'astuzia e all'intrigo.", desc: "Un artista in pietra al suo lavoro, che esibisce sotto forma di trofei." },
  "pe09": { meaning_up: "Prudenza, sicurezza, successo, realizzazione, certezza, discernimento.", meaning_rev: "Furfanteria, inganno, progetto annullato, cattiva fede.", desc: "Una donna, con un uccello sul polso, sta in mezzo a una grande abbondanza di vigne nel giardino di una casa signorile. È un vasto dominio, che suggerisce abbondanza in tutte le cose. Possibilmente è sua proprietà e testimonia il benessere materiale." },
  "pe10": { meaning_up: "Guadagno, ricchezze; questioni familiari, archivi, estrazione, la dimora di una famiglia.", meaning_rev: "Caso, fatalità, perdita, rapina, giochi d'azzardo; talvolta dono, dote, pensione.", desc: "Un uomo e una donna sotto un arco che dà accesso a una casa e un dominio. Sono accompagnati da un bambino, che guarda con curiosità due cani che accostano una figura antica seduta in primo piano. La mano del bambino è su uno di loro." },
  "swpa": { meaning_up: "Autorità, supervisione, servizio segreto, vigilanza, spionaggio, esame, e le qualità ad esso appartenenti.", meaning_rev: "Il lato più malvagio di queste qualità; ciò che è imprevisto, stato impreparato; anche la malattia è intimata.", desc: "Una figura agile e attiva tiene una spada dritta tra le mani, mentre compie veloci passi. Sta passando su terreno accidentato, e intorno al suo percorso le nuvole sono collocate selvaggiamente. È vigile e agile, guardando qua e là, come se un nemico atteso potesse apparire in qualsiasi momento." },
  "swkn": { meaning_up: "Abilità, coraggio, capacità, difesa, indirizzo, inimicizia, ira, guerra, distruzione, opposizione, resistenza, rovina. C'è quindi un senso in cui la carta significa morte, ma porta questo significato solo nella sua prossimità ad altre carte di fatalità.", meaning_rev: "Imprudenza, incapacità, stravaganza.", desc: "Sta cavalcando a pieno corso, come se disperdesse i suoi nemici. Nel disegno è veramente un eroe prototipico della cavalleria romantica. Potrebbe quasi essere Galad, la cui spada è veloce e sicura perché ha il cuore puro." },
  "swqu": { meaning_up: "Vedovanza, tristezza e imbarazzo femminile, assenza, sterilità, lutto, privazione, separazione.", meaning_rev: "Malvagità, bigottismo, artificio, pruderia, sventura, inganno.", desc: "La sua mano destra alza l'arma verticalmente e l'elsa poggia su un braccio della sua sedia reale; la mano sinistra è estesa, il braccio sollevato; il suo volto è severo ma placato; suggerisce familiarità con il dolore. Non rappresenta la misericordia, e, nonostante la sua spada, è scarsamente un simbolo di potenza." },
  "swki": { meaning_up: "Tutto ciò che nasce dall'idea del giudizio e da tutte le sue connessioni--potere, comando, autorità, intelligenza miliare, legge, uffici della corona, e così via.", meaning_rev: "Crudeltà, perversità, barbarie, perfidia, cattiva intenzione.", desc: "Siede nel giudizio, tenendo il segno non sguainato del suo seme. Ricorda, naturalmente, il Simbolo convenzionale della giustizia nei Trionfi Maggiori, e potrebbe rappresentare questa virtù, ma è piuttosto il potere della vita e della morte, in virtù del suo ufficio." },
  "swac": { meaning_up: "Trionfo, il grado eccessivo in tutto, conquista, trionfo della forza. È una carta di grande forza, nell'amore così come nell'odio. La corona può portare un significato molto più alto di quello che viene di solito nella sfera della lettura del futuro.", meaning_rev: "Lo stesso, ma i risultati sono disastrosi; un altro resoconto dice--concezione, parto, aumento, molteplicità.", desc: "Una mano esce da una nuvola, afferrando una parola, il cui punto è circondato da una corona." },
  "sw02": { meaning_up: "Conformità e l'equipoise che suggerisce, coraggio, amicizia, concordia in uno stato di armi; un'altra lettura dà tenerezza, affetto, intimità. Il suggerimento di armonia e altre letture favorevoli deve essere considerato in modo qualificato, in quanto le Spade generalmente non sono simboliche di forze benevole negli affari umani.", meaning_rev: "Impostura, falsità, duplicità, slealtà.", desc: "Una figura femminile bendare i fianchi due spade sulle spalle." },
  "sw03": { meaning_up: "Rimozione, assenza, ritardo, divisione, rottura, dispersione, e tutto ciò che il disegno significa naturalmente, essendo troppo semplice e ovvio per richiedere un'enumerazione specifica.", meaning_rev: "Alienazione mentale, errore, perdita, distrazione, disordine, confusione.", desc: "Tre spade che trafiggono un cuore; nuvola e pioggia dietro." },
  "sw04": { meaning_up: "Vigilanza, ritirata, solitudine, riposo dell'eremita, esilio, tomba e bara. Sono questi ultimi che hanno suggerito il disegno.", meaning_rev: "Saggia amministrazione, circospezione, economia, avarizia, precauzione, testamento.", desc: "L'effigie di un cavaliere nell'atteggiamento della preghiera, per intero sulla sua tomba." },
  "sw05": { meaning_up: "Degradazione, distruzione, revoca, infamia, disonore, perdita, con le varianti e i loro analoghi.", meaning_rev: "Lo stesso; sepoltura e esequie.", desc: "Un uomo di aspetto dispregiativo guarda dopo due figure che si ritirano e sono scoraggiate. Le loro spade giacciono per terra. Indossa altre due sulla spalla sinistra, e una terza spada è nella sua mano destra, con la punta verso la terra. È il maestro in possesso del campo." },
  "sw06": { meaning_up: "Viaggio per acqua, rotta, percorso, inviato, commissario, espediente.", meaning_rev: "Dichiarazione, confessione, pubblicità; un resoconto dice che è una proposta d'amore.", desc: "Un traghettatore che trasporta passeggeri nel suo battello verso l'altra sponda. Il corso è liscio, e vedendo che il carico è leggero, si può notare che il lavoro non è oltre la sua forza." },
  "sw07": { meaning_up: "Design, tentativo, desiderio, speranza, fiducia; anche litigio, un piano che potrebbe fallire, fastidio. Il disegno è incerto nel suo significato, perché i significati sono ampiamente divergenti l'uno dall'altro.", meaning_rev: "Buoni consigli, consiglio, istruzione, calunnia, ciarla.", desc: "Un uomo nell'atto di portare via cinque spade rapidamente; le altre due della carta rimangono conficcate nel terreno. Un accampamento è vicino." },
  "sw08": { meaning_up: "Cattive notizie, cruccio violento, crisi, censura, potenza nei lacci, conflitto, calunnia; anche malattia.", meaning_rev: "Inquietudine, difficoltà, opposizione, incidente, tradimento; ciò che è imprevisto; fatalità.", desc: "Una donna, legata e bendata, con le spade della carta intorno a lei. Eppure è piuttosto una carta di detenzione temporanea che di asservimento irreversibile." },
  "sw09": { meaning_up: "Morte, insuccesso, aborto, ritardo, inganno, delusione, disperazione.", meaning_rev: "Imprigionamento, sospetto, dubbio, paura ragionevole, vergogna.", desc: "Una seduta sul suo divano in lamentazione, con le spade sopra di lei. È come una che non conosce dolore che sia pari al suo. È una carta di utter desolazione." },
  "sw10": { meaning_up: "Qualunque cosa sia intimata dal disegno; anche dolore, afflizione, lacrime, tristezza, desolazione. Non è specialmente una carta di morte violenta.", meaning_rev: "Vantaggio, profitto, successo, favore, ma nessuno di questi è permanente; anche potenza e autorità.", desc: "Una figura prostrata, trafitta da tutte le spade appartenenti alla carta." },
};

const en = JSON.parse(fs.readFileSync('src/data/tarot-cards.json', 'utf8'));

const output = {
  nhits: en.nhits,
  cards: en.cards.map(card => {
    const trans = translations[card.name_short];
    return {
      ...card,
      meaning_up: trans?.meaning_up || card.meaning_up,
      meaning_rev: trans?.meaning_rev || card.meaning_rev,
      desc: trans?.desc || card.desc
    };
  })
};

fs.writeFileSync('src/data/tarot-cards-it.json', JSON.stringify(output, null, 2), 'utf8');
